"use client"
import React, { useState } from 'react';
import axios from 'axios';

const BlogForm = () => {
  const [blogData, setBlogData] = useState({
    title: '',
    description: '',
    category: '',
     // replace with actual user ID
  });
  const [thumbnail, setThumbnail] = useState(null);
  const [message, setMessage] = useState('');

  const handleChange = (e) => {
    setBlogData({ ...blogData, [e.target.name]: e.target.value });
  };

  const handleFileChange = (e) => {
    setThumbnail(e.target.files[0]);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    if (!thumbnail) {
      return setMessage("Please upload a thumbnail image");
    }

    const formData = new FormData();
    formData.append('title', blogData.title);
    formData.append('description', blogData.description);
    formData.append('category', blogData.category);
    formData.append('thumbnail', thumbnail); // Important: this must match `upload.single('thumbnail')`

    try {
      const res = await axios.post('http://localhost:5000/api/createblog', formData, {
        headers: {
          'Content-Type': 'multipart/form-data',
        },
      });

      setMessage(res.data.message || "Blog created successfully!");
    } catch (err) {
      setMessage(err.response?.data?.message || "Error creating blog");
    }
  };

  return (
    <div style={{ maxWidth: "500px", margin: "auto", padding: "20px" }}>
      <h2>Create Blog</h2>
      <form onSubmit={handleSubmit}>
        <input type="text" name="title" placeholder="Title" onChange={handleChange} required /><br /><br />
        <textarea name="description" placeholder="Description" onChange={handleChange} required></textarea><br /><br />
        <input type="text" name="category" placeholder="Category" onChange={handleChange} required /><br /><br />
        <input type="file" accept="image/*" onChange={handleFileChange} /><br /><br />
        <button type="submit">Submit</button>
      </form>
      {message && <p style={{ color: "green" }}>{message}</p>}
    </div>
  );
};

export default BlogForm;
